    InventTable                         inventTable;
    InventTrans                         inventtrans,inventtrans1;
    // InventTable                  inventtrans1;
    InventTransOrigin                   inventTransOrigin;
    InventDim                           inventDim,inventDimTot,inventDimLocal,inventDimLoc;
    InventBatch                         inventBatch;
    InventItemGroup                     inventItemGroup;
    InventItemGroupItem                 inventItemGroupItem;
    ItemId                              _itemid;
    InventDimId                         inventdimid;
    InventSum                           inventSum;
    InventTrans                         openInventTransIn,openInventTransOut,grnInventTrans,invoicegrnInventTrans,returnInventTrans,stockInventTransIn,stockInventTransOut,purchtransitInventTrans,soldtransitInventTrans,transferJourTransIn,transferJourTransOut,salesInventTrans, closingInventTrans,
                                        prodInventTrans,prodReceivedInventTrans,consInventTrans,consDeductedInventTrans,salespickedInventTrans,inventAdjgainInventTrans,inventAdjLossInventTrans,movementjourInventTransIn,movementjourInventTransOut,salesCOGSInventTrans,salesreturnInventTrans;
    InventTransferJour                  inventTransferJour;
    InventTransferJourLine              inventTransferJourLine;
    ProdJournalBOM                      prodJournalBOM;
